import { el, table } from './dom-helpers.js';
import { STRATEGIES } from '../engine/scenario-runner.js';
import { getImportPreviewRows } from '../import/import-to-plan-input.js';
import { CONTAINER_SPECS } from '../domain/container.js';

export function createImportPage(onImport) {
  const fileInput = el('input', { type: 'file', className: 'file-input', accept: '.xlsx,.xls,.csv' });
  const strategySelect = el('select', { className: 'strategy-mode' });
  for (const strategy of STRATEGIES) {
    strategySelect.appendChild(el('option', { value: strategy.name, textContent: strategy.label }));
  }

  const containerSelect = el('select', { className: 'import-container-select' });
  for (const [name, spec] of Object.entries(CONTAINER_SPECS)) {
    containerSelect.appendChild(el('option', {
      value: name,
      textContent: `${name} (${spec.length}×${spec.width}×${spec.height}mm, ${spec.maxWeight}kg)`,
    }));
  }
  const statusArea = el('div', { className: 'import-status' });
  const previewArea = el('div', { className: 'import-preview' });
  const confirmBtn = el('button', { className: 'import-confirm-btn', textContent: '确认导入', style: { display: 'none' } });

  let pendingResult = null;

  fileInput.addEventListener('change', async (event) => {
    const file = event.target.files[0];
    if (!file) return;

    statusArea.textContent = `正在读取: ${file.name}...`;
    previewArea.textContent = '';
    confirmBtn.style.display = 'none';

    try {
      const arrayBuffer = await file.arrayBuffer();
      const { importWorkbook, initAdapters } = await import('../import/import-service.js');
      initAdapters();
      const result = importWorkbook(arrayBuffer);
      pendingResult = result;

      const { summary } = result;
      statusArea.textContent = '';
      statusArea.appendChild(el('div', { className: 'import-summary' }, [
        el('span', { textContent: `已处理 ${summary.sheetsProcessed} 个工作表` }),
        el('span', { textContent: ` | 产品: ${summary.productsFound}` }),
        el('span', { textContent: ` | 箱型: ${summary.cartonsFound}` }),
        el('span', { textContent: ` | 托盘: ${summary.palletsFound}` }),
        el('span', { textContent: ` | 需求行: ${summary.demandLinesFound}` }),
        el('span', { textContent: ` | 货柜: ${containerSelect.value}` }),
        el('span', { textContent: ` | 尺寸单位检测: ${result.dimensionUnit?.inputUnit || 'unknown'} → mm` }),
      ]));

      if (result.totalErrors > 0) {
        const errorHeaders = ['行号', '字段', '错误信息'];
        const errorRows = result.errors.slice(0, 20).map((error) => [String(error.row), error.field, error.message]);
        statusArea.appendChild(el('div', { className: 'import-errors' }, [
          el('h4', { textContent: `发现 ${result.totalErrors} 个错误` }),
          table(errorHeaders, errorRows),
        ]));
      }

      if (result.cartons.length > 0) {
        const previewHeaders = ['产品编码', '长mm', '宽mm', '高mm', '重量kg', '原始箱数', '计算数量', '数量来源'];
        const previewRows = getImportPreviewRows(result, 10).map((row) => [
          row.productCode,
          row.length,
          row.width,
          row.height,
          row.weight,
          row.rawCartonQty,
          row.calculatedQty,
          row.quantitySource,
        ]);
        previewArea.textContent = '';
        previewArea.appendChild(el('h4', { textContent: '数据预览（前10行）' }));
        previewArea.appendChild(table(previewHeaders, previewRows));
      }

      confirmBtn.style.display = 'block';
    } catch (error) {
      statusArea.textContent = `导入失败: ${error.message}`;
      pendingResult = null;
    }
  });

  confirmBtn.addEventListener('click', () => {
    if (pendingResult && onImport) {
      onImport({ importResult: pendingResult, strategyMode: strategySelect.value, containerType: containerSelect.value });
      statusArea.textContent = '导入成功！';
      confirmBtn.style.display = 'none';
    }
  });

  const page = el('div', { className: 'import-page' }, [
    el('h2', { textContent: 'Excel 导入' }),
    el('div', { className: 'form-section' }, [
      el('p', { textContent: '支持 .xlsx / .xls / .csv 格式，自动识别工作表类型和多语言表头。' }),
      fileInput,
    ]),
    el('div', { className: 'form-section' }, [
      el('h3', { textContent: '方案模式' }),
      strategySelect,
    ]),
    el('div', { className: 'form-section' }, [
      el('h3', { textContent: '货柜选择' }),
      containerSelect,
    ]),
    statusArea,
    previewArea,
    confirmBtn,
  ]);

  return page;
}
