import { EPSILON, DENSITY_TOLERANCE } from './epsilon.js';

export function checkBoundary(absX, absY, absZ, L, W, H, usableLength, usableWidth, usableHeight) {
  return (absX + L <= usableLength + EPSILON)
    && (absY + W <= usableWidth + EPSILON)
    && (absZ + H <= usableHeight + EPSILON);
}

export function checkLayerLimit(layerRule, zLayer) {
  if (layerRule === 'max4' && zLayer > 4) return false;
  return true;
}

export function checkHeavyBottom(strictStack, item, zLayer, supportBelow) {
  if (!strictStack || zLayer === 0) return true;
  if (!supportBelow.length) return true;
  const underHasLight = supportBelow.some(u => u.isLight);
  const underAvgDensity = supportBelow.reduce((s, u) => s + u.density, 0) / supportBelow.length;
  if (item.heavy && underHasLight) return false;
  if (item.heavy && item.density > underAvgDensity * DENSITY_TOLERANCE) return false;
  return true;
}

export function checkWeightCap(itemWeight, currentWeight, maxWeight) {
  if (itemWeight <= 0) return Infinity;
  return Math.floor((maxWeight - currentWeight) / itemWeight);
}

export function calcBalance(placements, usableLength) {
  if (placements.length === 0) return 0;
  const mid = usableLength / 2;
  const frontQty = placements.filter(p => p.absX < mid).length;
  const rearQty = placements.length - frontQty;
  return Math.abs(frontQty - rearQty) / placements.length * 100;
}

export function calcWeightedBalance(placements, usableLength, itemWeights) {
  if (placements.length === 0) return 0;
  const mid = usableLength / 2;
  let frontWeight = 0;
  let rearWeight = 0;
  for (const p of placements) {
    const w = itemWeights ? (itemWeights.get(p.name) || p.weight || 0) : (p.weight || 0);
    if (p.absX + p.L / 2 < mid) frontWeight += w;
    else rearWeight += w;
  }
  const total = frontWeight + rearWeight;
  return total > 0 ? Math.abs(frontWeight - rearWeight) / total * 100 : 0;
}

export function checkCompliance(ctx) {
  const { totalWeight, maxWeight, usableHeight, usableLength, usableWidth,
    placements, cursorX, hardFailures, balanceDiff, balanceLimit } = ctx;
  return [
    { name: '总重量合规', ok: totalWeight <= maxWeight, note: '总重量不得超过货柜最大载重' },
    { name: '顶部余量合规', ok: usableHeight >= 0 && placements.every(p => p.absZ + p.H <= usableHeight + EPSILON), note: '每个箱体都必须落在可用净高以内' },
    { name: '柜门预留合规', ok: cursorX <= usableLength + EPSILON, note: '已预留柜门操作距离且未侵占' },
    { name: '侧向余量合规', ok: usableWidth >= 0 && placements.every(p => p.absY + p.W <= usableWidth + EPSILON), note: '每个箱体都必须落在柜内有效宽度以内' },
    { name: '重货层位合规', ok: placements.every(p => p.layerRule !== 'max4' || (Math.floor(p.absZ / p.H) < 4)), note: 'A箱/限制箱仅允许出现在第1-4层' },
    { name: '重下轻上合规', ok: !hardFailures.some(x => x.includes('重下轻上')), note: '重货优先底层，轻货不承托更重货物' },
    { name: '配重均衡合规', ok: balanceDiff <= balanceLimit, note: '前后配重偏差不宜过大' },
    { name: '硬约束越界校验', ok: !hardFailures.some(x => x.includes('越界')), note: hardFailures.length ? hardFailures.join('；') : '未发现超柜体摆放' },
  ];
}
