import { runFloorPlan } from './placer.js';

export const STRATEGIES = Object.freeze([
  {
    name: 'baseline',
    label: '稳妥基准方案',
    sort: (a, b) => {
      if (a.heavy !== b.heavy) return a.heavy ? -1 : 1;
      if (a.layerRule !== b.layerRule) return a.layerRule === 'max4' ? -1 : 1;
      return (b.L * b.W * b.H) - (a.L * a.W * a.H);
    },
  },
  {
    name: 'qty-priority',
    label: '最大装载量优先',
    sort: (a, b) => (b.qty - a.qty) || ((b.L * b.W * b.H) - (a.L * a.W * a.H)),
  },
  {
    name: 'fewer-containers',
    label: '大底面积箱优先',
    sort: (a, b) => ((b.L * b.W) - (a.L * a.W)) || (b.weight - a.weight),
  },
  {
    name: 'weight-balanced',
    label: '重量均衡优先',
    sort: (a, b) => (b.weight - a.weight) || (b.qty - a.qty),
  },
]);

export const DEFAULT_STRATEGY = STRATEGIES[0].name;

function cloneItems(items) {
  return items.map((item) => ({ ...item }));
}

function rebucket(sortedItems) {
  const heavy = sortedItems.filter((item) => item.heavy && !item.isLight);
  const normal = sortedItems.filter((item) => !item.heavy && !item.isLight);
  const light = sortedItems.filter((item) => item.isLight);
  return [...heavy, ...normal, ...light];
}

function normalizeStrategyMode(strategyMode) {
  return STRATEGIES.some((strategy) => strategy.name === strategyMode) ? strategyMode : DEFAULT_STRATEGY;
}

export function getStrategyLabel(strategyMode) {
  return STRATEGIES.find((strategy) => strategy.name === normalizeStrategyMode(strategyMode))?.label || STRATEGIES[0].label;
}

export function runAllStrategies(items, container, options = {}) {
  const selectedStrategy = normalizeStrategyMode(options.strategyMode);
  const rawResults = [];

  for (const strategy of STRATEGIES) {
    const cloned = cloneItems(items);
    cloned.sort(strategy.sort);
    const ordered = rebucket(cloned);

    const result = runFloorPlan(ordered, container, options);
    const unfitQty = result.failureDiagnostics.reduce((sum, failure) => sum + failure.diff, 0);

    rawResults.push({
      strategy: strategy.name,
      label: strategy.label,
      totalQty: result.totalQty,
      unfitQty,
      totalWeight: result.totalWeight,
      totalVolume: result.totalVolume,
      volumeRate: result.volumeRate,
      weightRate: result.weightRate,
      placements: result.placements,
      details: result.details,
      failureDiagnostics: result.failureDiagnostics,
      hardFailures: result.hardFailures,
      cursorX: result.cursorX,
    });
  }

  const results = rawResults
    .sort((a, b) => (b.totalQty - a.totalQty) || (a.unfitQty - b.unfitQty) || (b.volumeRate - a.volumeRate))
    .map((result) => ({
      ...result,
      selected: result.strategy === selectedStrategy,
    }));

  return {
    results,
    best: results.find((result) => result.strategy === selectedStrategy) || results[0] || null,
    selectedStrategy,
    selectedStrategyLabel: getStrategyLabel(selectedStrategy),
  };
}
