function parseJsonResponse(text) {
  return text ? JSON.parse(text) : null;
}

async function request(path = '', options = {}) {
  const res = await fetch(`/api/history${path}`, {
    headers: { 'Content-Type': 'application/json' },
    ...options,
  });

  if (!res.ok) {
    throw new Error(`History API error: ${res.status} ${res.statusText}`);
  }

  return parseJsonResponse(await res.text());
}

export async function listHistory() {
  const payload = await request('');
  return Array.isArray(payload?.records) ? payload.records : [];
}

export async function saveHistoryRecord(record) {
  const payload = await request('', {
    method: 'POST',
    body: JSON.stringify(record),
  });
  return Array.isArray(payload?.records) ? payload.records : [];
}

export async function loadHistoryRecord(id) {
  return request(`/${encodeURIComponent(id)}`);
}

export async function deleteHistoryRecord(id) {
  const payload = await request(`/${encodeURIComponent(id)}`, {
    method: 'DELETE',
  });
  return Array.isArray(payload?.records) ? payload.records : [];
}

export async function clearHistory() {
  const payload = await request('', {
    method: 'DELETE',
  });
  return Array.isArray(payload?.records) ? payload.records : [];
}
