import { runAllStrategies } from './scenario-runner.js';
import { calcBalance, checkCompliance } from './constraints.js';
import { WEIGHT_WARNING_THRESHOLD } from './epsilon.js';
import { CONTAINER_SPECS } from '../domain/container.js';
import { calcCenterOfGravity, calcCogDeviation } from './cog.js';

export function planLoad(items, container, options = {}) {
  const { balanceLimit = 15 } = options;
  const { results, best, selectedStrategy, selectedStrategyLabel } = runAllStrategies(items, container, options);

  if (!best) {
    return {
      best: null,
      strategies: results,
      compliance: [],
      suggestions: [],
      selectedStrategy,
      selectedStrategyLabel,
    };
  }

  const balanceDiff = calcBalance(best.placements, container.usableLength);

  const compliance = checkCompliance({
    totalWeight: best.totalWeight,
    maxWeight: container.maxWeight,
    usableHeight: container.usableHeight,
    usableLength: container.usableLength,
    usableWidth: container.usableWidth,
    placements: best.placements,
    cursorX: best.cursorX,
    hardFailures: best.hardFailures,
    balanceDiff,
    balanceLimit,
  });

  const suggestions = [];
  if (best.weightRate > WEIGHT_WARNING_THRESHOLD) {
    suggestions.push({ type: '重量预警', message: '重量利用率过高，建议分柜或调整重货比例' });
  }
  if (best.failureDiagnostics.length > 0) {
    suggestions.push({ type: '装载不完整', message: `有 ${best.failureDiagnostics.length} 种货物未能完全装入，建议换柜型或拆分多柜` });
  }

  const cog = calcCenterOfGravity(best.placements, null);
  const cogDeviation = calcCogDeviation(cog, {
    length: container.usableLength,
    width: container.usableWidth,
    height: container.usableHeight,
  });

  return {
    best: {
      ...best,
      balanceDiff,
      cog,
      cogDeviation,
    },
    strategies: results,
    compliance,
    suggestions,
    selectedStrategy,
    selectedStrategyLabel,
  };
}

export function compareContainers(items, options = {}) {
  const { doorGap = 0, topGap = 0, sideGap = 0, palletH = 0 } = options;

  const containerVariants = Object.entries(CONTAINER_SPECS).map(([name, spec]) => ({
    name,
    usableLength: spec.length - doorGap,
    usableWidth: spec.width - sideGap * 2,
    usableHeight: spec.height - topGap - palletH,
    maxWeight: spec.maxWeight,
  }));

  const containerResults = containerVariants.map((containerVariant) => {
    const { best } = runAllStrategies(items, containerVariant, options);
    const unfitQty = best ? best.failureDiagnostics.reduce((sum, failure) => sum + failure.diff, 0) : items.reduce((sum, item) => sum + item.qty, 0);
    return {
      name: containerVariant.name,
      L: containerVariant.usableLength + doorGap,
      W: containerVariant.usableWidth + sideGap * 2,
      H: containerVariant.usableHeight + topGap + palletH,
      maxWeight: containerVariant.maxWeight,
      totalQty: best ? best.totalQty : 0,
      unfitQty,
      volumeRate: best ? best.volumeRate : 0,
      weightRate: best ? best.weightRate : 0,
    };
  });

  containerResults.sort((a, b) =>
    (b.totalQty - a.totalQty) || (a.unfitQty - b.unfitQty) || (b.volumeRate - a.volumeRate),
  );

  const bestContainer = containerResults[0];
  const ranked = containerResults.map((entry, index) => ({
    ...entry,
    reason: index === 0
      ? '当前货量下综合最优柜型'
      : entry.totalQty < bestContainer.totalQty
        ? `比最优少装 ${bestContainer.totalQty - entry.totalQty} 箱`
        : entry.unfitQty > bestContainer.unfitQty
          ? `比最优多剩余 ${entry.unfitQty - bestContainer.unfitQty} 箱`
          : '装箱数接近，但利用率或均衡性略弱',
  }));

  return {
    results: ranked,
    best: ranked[0] || null,
  };
}
