import { el } from './dom-helpers.js';
import { CONTAINER_SPECS } from '../domain/container.js';
import { STRATEGIES } from '../engine/scenario-runner.js';

function formatHistoryTime(createdAt) {
  try {
    return new Date(createdAt).toLocaleString('zh-CN', { hour12: false });
  } catch {
    return createdAt || '-';
  }
}

function getHistorySummary(record) {
  const input = record.input || {};
  const items = Array.isArray(input.items) ? input.items : [];
  const itemTypes = record.summary?.itemTypes ?? items.length;
  const totalQty = record.summary?.totalQty ?? items.reduce((sum, item) => sum + (Number(item.qty) || 0), 0);
  const strategyLabel = record.summary?.strategyLabel
    || STRATEGIES.find((strategy) => strategy.name === input.strategyMode)?.label
    || STRATEGIES[0].label;

  return {
    sourceLabel: record.summary?.sourceLabel || (record.source === 'excel-import' ? 'Excel 导入' : '快速计算'),
    containerType: record.summary?.containerType || input.container?.type || 'custom',
    itemTypes,
    totalQty,
    strategyLabel,
    importFileName: record.summary?.importFileName || '',
  };
}

export function createQuickCalcPage(onCalculate, options = {}) {
  const {
    initialInput = null,
    historyRecords: initialHistoryRecords = [],
    historyAvailable = true,
    onLoadHistory = null,
    onDeleteHistory = null,
    onClearHistory = null,
  } = options;

  const containerSelect = el('select', { className: 'container-select' });
  for (const [name, spec] of Object.entries(CONTAINER_SPECS)) {
    const option = el('option', { value: name, textContent: `${name} (${spec.length}×${spec.width}×${spec.height}mm, ${spec.maxWeight}kg)` });
    containerSelect.appendChild(option);
  }
  containerSelect.appendChild(el('option', { value: 'custom', textContent: '自定义柜型' }));

  const strategySelect = el('select', { className: 'strategy-mode' });
  for (const strategy of STRATEGIES) {
    strategySelect.appendChild(el('option', { value: strategy.name, textContent: strategy.label }));
  }

  const customLengthInput = el('input', { className: 'custom-length', type: 'number', value: '1200' });
  const customWidthInput = el('input', { className: 'custom-width', type: 'number', value: '235' });
  const customHeightInput = el('input', { className: 'custom-height', type: 'number', value: '269' });
  const customWeightInput = el('input', { className: 'custom-weight', type: 'number', value: '26500' });

  const customFields = el('div', { className: 'custom-container-fields', style: { display: 'none' } }, [
    el('label', { textContent: '长(mm)' }), customLengthInput,
    el('label', { textContent: '宽(mm)' }), customWidthInput,
    el('label', { textContent: '高(mm)' }), customHeightInput,
    el('label', { textContent: '载重(kg)' }), customWeightInput,
  ]);

  containerSelect.addEventListener('change', () => {
    customFields.style.display = containerSelect.value === 'custom' ? 'block' : 'none';
  });

  const doorGapInput = el('input', { className: 'door-gap', type: 'number', value: '0' });
  const topGapInput = el('input', { className: 'top-gap', type: 'number', value: '0' });
  const sideGapInput = el('input', { className: 'side-gap', type: 'number', value: '0' });

  const cargoList = el('div', { className: 'cargo-list' });
  const cargoItems = [];
  let historyRecords = Array.isArray(initialHistoryRecords) ? initialHistoryRecords : [];

  function removeCargoItem(item) {
    if (item.parentNode === cargoList) {
      cargoList.removeChild(item);
    }

    const index = cargoItems.indexOf(item);
    if (index >= 0) {
      cargoItems.splice(index, 1);
    }
  }

  function addCargoItem(data = {}) {
    const item = el('div', { className: 'cargo-item' }, [
      el('input', { className: 'name', type: 'text', value: data.name || '', placeholder: '货物名称' }),
      el('input', { className: 'cargo-L', type: 'number', value: String(data.L || ''), placeholder: '长mm' }),
      el('input', { className: 'cargo-W', type: 'number', value: String(data.W || ''), placeholder: '宽mm' }),
      el('input', { className: 'cargo-H', type: 'number', value: String(data.H || ''), placeholder: '高mm' }),
      el('input', { className: 'cargo-weight', type: 'number', value: String(data.weight || ''), placeholder: '重量kg' }),
      el('input', { className: 'cargo-qty', type: 'number', value: String(data.qty || ''), placeholder: '数量' }),
      el('button', { className: 'remove-cargo', textContent: '删除', onClick: () => removeCargoItem(item) }),
    ]);
    cargoItems.push(item);
    cargoList.appendChild(item);
    return item;
  }

  function clearCargoItems() {
    while (cargoItems.length > 0) {
      removeCargoItem(cargoItems[0]);
    }
  }

  function applyInputData(inputData = {}) {
    const container = inputData.container || {};
    const containerType = container.type === 'custom' || CONTAINER_SPECS[container.type]
      ? container.type
      : Object.keys(CONTAINER_SPECS)[0];

    containerSelect.value = containerType || Object.keys(CONTAINER_SPECS)[0];
    customFields.style.display = containerSelect.value === 'custom' ? 'block' : 'none';

    customLengthInput.value = String(container.length ?? 1200);
    customWidthInput.value = String(container.width ?? 235);
    customHeightInput.value = String(container.height ?? 269);
    customWeightInput.value = String(container.maxWeight ?? 26500);
    doorGapInput.value = String(inputData.doorGap ?? 0);
    topGapInput.value = String(inputData.topGap ?? 0);
    sideGapInput.value = String(inputData.sideGap ?? 0);
    strategySelect.value = STRATEGIES.some((strategy) => strategy.name === inputData.strategyMode)
      ? inputData.strategyMode
      : STRATEGIES[0].name;

    clearCargoItems();
    const items = Array.isArray(inputData.items) && inputData.items.length > 0 ? inputData.items : [{}];
    items.forEach((item) => addCargoItem(item));
  }

  function getInputData() {
    const containerType = containerSelect.value;
    let container;
    if (containerType === 'custom') {
      container = {
        type: 'custom',
        length: +customLengthInput.value,
        width: +customWidthInput.value,
        height: +customHeightInput.value,
        maxWeight: +customWeightInput.value,
      };
    } else {
      const spec = CONTAINER_SPECS[containerType];
      container = { type: containerType, ...spec };
    }

    const doorGap = +doorGapInput.value || 0;
    const topGap = +topGapInput.value || 0;
    const sideGap = +sideGapInput.value || 0;

    const items = cargoItems.map((itemEl, index) => ({
      name: itemEl.querySelector('.name').value || `箱型${index + 1}`,
      L: +itemEl.querySelector('.cargo-L').value,
      W: +itemEl.querySelector('.cargo-W').value,
      H: +itemEl.querySelector('.cargo-H').value,
      weight: +itemEl.querySelector('.cargo-weight').value,
      qty: +itemEl.querySelector('.cargo-qty').value,
      heavy: false,
      isLight: false,
      density: 0,
      layerRule: 'none',
      sideAllowed: true,
      color: 0x4f46e5,
    })).filter((item) => item.L > 0 && item.W > 0 && item.H > 0 && item.qty > 0);

    return {
      container,
      items,
      doorGap,
      topGap,
      sideGap,
      strategyMode: strategySelect.value,
    };
  }

  const addBtn = el('button', { className: 'add-cargo-btn', textContent: '+ 添加货物', onClick: () => addCargoItem() });
  const calcBtn = el('button', {
    className: 'calc-btn',
    textContent: '开始计算',
    onClick: () => {
      if (onCalculate) onCalculate(getInputData(), { source: 'manual' });
    },
  });

  const historyList = el('div', { className: 'history-list' });
  const clearHistoryBtn = el('button', {
    className: 'clear-history-btn',
    textContent: '清空历史',
    onClick: async () => {
      const nextHistory = onClearHistory ? await onClearHistory() : [];
      historyRecords = Array.isArray(nextHistory) ? nextHistory : [];
      renderHistory();
    },
  });

  async function handleLoad(recordId) {
    const loadedInput = onLoadHistory ? await onLoadHistory(recordId) : null;
    if (!loadedInput) return;

    applyInputData(loadedInput);
    if (onCalculate) {
      await onCalculate(getInputData(), { source: 'history-load', historyId: recordId });
    }
  }

  async function handleDelete(recordId) {
    const nextHistory = onDeleteHistory
      ? await onDeleteHistory(recordId)
      : historyRecords.filter((record) => record.id !== recordId);
    historyRecords = Array.isArray(nextHistory)
      ? nextHistory
      : historyRecords.filter((record) => record.id !== recordId);
    renderHistory();
  }

  function renderHistory() {
    historyList.textContent = '';

    if (!historyAvailable) {
      clearHistoryBtn.style.display = 'none';
      historyList.appendChild(el('p', { className: 'history-unavailable', textContent: '历史记录当前不可用' }));
      return;
    }

    clearHistoryBtn.style.display = historyRecords.length > 0 ? 'inline-flex' : 'none';

    if (historyRecords.length === 0) {
      historyList.appendChild(el('p', { className: 'history-empty', textContent: '暂无历史记录' }));
      return;
    }

    historyRecords.forEach((record) => {
      const summary = getHistorySummary(record);
      const metaParts = [
        summary.sourceLabel,
        summary.containerType,
        `货物条目数 ${summary.itemTypes}`,
        `总件数 ${summary.totalQty}`,
        `策略 ${summary.strategyLabel}`,
      ];
      if (summary.importFileName) metaParts.push(`文件 ${summary.importFileName}`);

      historyList.appendChild(el('div', { className: 'history-record' }, [
        el('div', { className: 'history-record-header' }, [
          el('strong', { className: 'history-record-title', textContent: formatHistoryTime(record.createdAt) }),
        ]),
        el('div', { className: 'history-record-meta', textContent: metaParts.join(' / ') }),
        el('div', { className: 'history-record-actions' }, [
          el('button', {
            className: 'history-load-btn',
            textContent: '加载并计算',
            onClick: () => {
              void handleLoad(record.id);
            },
          }),
          el('button', {
            className: 'history-delete-btn',
            textContent: '删除',
            onClick: () => {
              void handleDelete(record.id);
            },
          }),
        ]),
      ]));
    });
  }

  if (initialInput) {
    applyInputData(initialInput);
  } else {
    addCargoItem();
  }

  renderHistory();

  return el('div', { className: 'quick-calc-page' }, [
    el('h2', { textContent: '快速计算' }),
    el('div', { className: 'form-section' }, [
      el('h3', { textContent: '柜型选择' }),
      containerSelect,
      customFields,
    ]),
    el('div', { className: 'form-section' }, [
      el('h3', { textContent: '方案模式' }),
      strategySelect,
    ]),
    el('div', { className: 'form-section' }, [
      el('h3', { textContent: '间距设置' }),
      el('label', { textContent: '柜门预留(mm)' }), doorGapInput,
      el('label', { textContent: '顶部余量(mm)' }), topGapInput,
      el('label', { textContent: '侧向余量(mm)' }), sideGapInput,
    ]),
    el('div', { className: 'form-section' }, [
      el('h3', { textContent: '货物列表' }),
      cargoList,
      addBtn,
    ]),
    calcBtn,
    el('div', { className: 'form-section history-section' }, [
      el('div', { className: 'history-header' }, [
        el('h3', { textContent: '最近 5 次历史记录' }),
        clearHistoryBtn,
      ]),
      historyList,
    ]),
  ]);
}
