export function calcCenterOfGravity(placements, itemWeightMap) {
  if (!placements || placements.length === 0) {
    return { cogX: 0, cogY: 0, cogZ: 0, totalWeight: 0 };
  }

  let totalWeight = 0;
  let momentX = 0;
  let momentY = 0;
  let momentZ = 0;

  for (const p of placements) {
    const w = itemWeightMap ? (itemWeightMap.get(p.name) || 0) : (p.weight || 0);
    totalWeight += w;
    momentX += w * (p.absX + p.L / 2);
    momentY += w * (p.absY + p.W / 2);
    momentZ += w * (p.absZ + p.H / 2);
  }

  if (totalWeight === 0) {
    return { cogX: 0, cogY: 0, cogZ: 0, totalWeight: 0 };
  }

  return {
    cogX: momentX / totalWeight,
    cogY: momentY / totalWeight,
    cogZ: momentZ / totalWeight,
    totalWeight,
  };
}

export function calcCogDeviation(cog, containerDims) {
  const { cogX, cogY, cogZ } = cog;
  const { length, width, height } = containerDims;
  const centerX = length / 2;
  const centerY = width / 2;
  const centerZ = height / 2;

  return {
    deviationX: length > 0 ? ((cogX - centerX) / length) * 100 : 0,
    deviationY: width > 0 ? ((cogY - centerY) / width) * 100 : 0,
    deviationZ: height > 0 ? ((cogZ - centerZ) / height) * 100 : 0,
    distanceFromCenter: Math.sqrt(
      Math.pow(cogX - centerX, 2) +
      Math.pow(cogY - centerY, 2) +
      Math.pow(cogZ - centerZ, 2)
    ),
  };
}
