export const EPSILON = 1e-9;
export const DENSITY_TOLERANCE = 1.05;
export const PALLET_FILL_THRESHOLD = 0.85;
export const WEIGHT_WARNING_THRESHOLD = 95;

export function fitsWithin(value, limit) {
  return value <= limit + EPSILON;
}

export function approxEqual(a, b) {
  return Math.abs(a - b) <= EPSILON;
}
