export function el(tag, attrs = {}, children = []) {
  const element = document.createElement(tag);
  for (const [key, value] of Object.entries(attrs)) {
    if (key === 'textContent') {
      element.textContent = value;
    } else if (key === 'className') {
      element.className = value;
    } else if (key === 'style' && typeof value === 'object') {
      Object.assign(element.style, value);
    } else if (key.startsWith('on') && typeof value === 'function') {
      element.addEventListener(key.slice(2).toLowerCase(), value);
    } else {
      element.setAttribute(key, value);
    }
  }
  for (const child of children) {
    if (typeof child === 'string') {
      element.appendChild(document.createTextNode(child));
    } else if (child) {
      element.appendChild(child);
    }
  }
  return element;
}

export function text(content) {
  return document.createTextNode(String(content));
}

export function row(cells) {
  return el('tr', {}, cells.map(c =>
    typeof c === 'string' || typeof c === 'number'
      ? el('td', { textContent: String(c) })
      : el('td', {}, [c])
  ));
}

export function cell(content, tag = 'td') {
  return el(tag, { textContent: String(content) });
}

export function table(headers, rows) {
  const thead = el('thead', {}, [
    el('tr', {}, headers.map(h => el('th', { textContent: String(h) }))),
  ]);
  const tbody = el('tbody', {}, rows.map(r => row(r)));
  return el('table', {}, [thead, tbody]);
}
