export function getOrientations(item) {
  const options = [
    { name: '正放', L: item.L, W: item.W, H: item.H },
    { name: '旋转平放', L: item.W, W: item.L, H: item.H },
  ];
  if (item.sideAllowed) {
    options.push({ name: '侧放1', L: item.L, W: item.H, H: item.W });
    options.push({ name: '侧放2', L: item.W, W: item.H, H: item.L });
  }
  const uniq = new Map();
  for (const opt of options) {
    const key = `${opt.L}:${opt.W}:${opt.H}`;
    if (!uniq.has(key)) uniq.set(key, opt);
  }
  return [...uniq.values()];
}
