import { createAppShell } from './ui/app-shell.js';
import { createQuickCalcPage } from './ui/quick-calc.js';
import { createImportPage } from './ui/import-page.js';
import { createResultPage } from './ui/result-page.js';
import { planLoad } from './engine/engine-service.js';
import { createViewModel, assignColors } from './presentation/view-model.js';
import { draw2D } from './presentation/renderer-2d.js';
import { create3DRenderer } from './presentation/renderer-3d.js';
import { transformImportResultToPlanInput } from './import/import-to-plan-input.js';
import { getStrategyLabel } from './engine/scenario-runner.js';
import * as historyApi from './history/history-api.js';

const app = document.getElementById('app');
const shell = createAppShell(app);
const resultPage = createResultPage();
let renderer3d = null;
let latestViewModel = null;
let latestCalculationInput = null;
let historyRecords = [];

function cloneCalculationInput(inputData) {
  if (!inputData) return null;
  return {
    container: inputData.container ? { ...inputData.container } : null,
    items: Array.isArray(inputData.items) ? inputData.items.map((item) => ({ ...item })) : [],
    doorGap: inputData.doorGap ?? 0,
    topGap: inputData.topGap ?? 0,
    sideGap: inputData.sideGap ?? 0,
    strategyMode: inputData.strategyMode,
  };
}

async function refreshHistory() {
  try {
    historyRecords = await historyApi.listHistory();
  } catch {
    historyRecords = [];
  }
}

function getQuickCalcPageOptions() {
  return {
    historyRecords,
    historyAvailable: true,
    onLoadHistory: handleLoadHistory,
    onDeleteHistory: handleDeleteHistory,
    onClearHistory: handleClearHistory,
  };
}

async function handleLoadHistory(id) {
  try {
    const record = await historyApi.loadHistoryRecord(id);
    if (!record?.input) return null;
    return cloneCalculationInput(record.input);
  } catch {
    return null;
  }
}

async function handleDeleteHistory(id) {
  try {
    historyRecords = await historyApi.deleteHistoryRecord(id);
  } catch {
    historyRecords = historyRecords.filter((r) => r.id !== id);
  }
  return historyRecords;
}

async function handleClearHistory() {
  try {
    historyRecords = await historyApi.clearHistory();
  } catch {
    historyRecords = [];
  }
  return historyRecords;
}

function dispose3DRenderer() {
  if (renderer3d) {
    try { renderer3d.dispose(); } catch (_e) { void _e; }
    renderer3d = null;
  }
  if (resultPage.view3dContainer) {
    resultPage.view3dContainer.textContent = '';
  }
}

function render2D(vm) {
  if (!resultPage.canvas2d || !vm?.renderData) return;
  draw2D(resultPage.canvas2d, vm.renderData);
}

function render2DIfNeeded() {
  if (!latestViewModel?.renderData || !resultPage.is2DTabActive()) return;
  render2D(latestViewModel);
}

function render3DIfNeeded() {
  if (!latestViewModel?.renderData || !resultPage.is3DTabActive()) return;
  const hasPlacements = (latestViewModel.renderData.placements || []).length > 0;
  if (!hasPlacements) { dispose3DRenderer(); return; }
  if (!renderer3d) { renderer3d = create3DRenderer(resultPage.view3dContainer); }
  try {
    renderer3d.draw(latestViewModel.renderData);
    renderer3d.resize();
  } catch (_e) { void _e; dispose3DRenderer(); }
}

function renderResult(vm) {
  latestViewModel = vm;
  resultPage.update(vm);
  shell.showPage('result');
  render2DIfNeeded();
  if ((vm.renderData?.placements || []).length === 0) { dispose3DRenderer(); return; }
  render3DIfNeeded();
}

function renderEmptyResult(container, strategyMode) {
  const vm = createViewModel({
    best: null, strategies: [], compliance: [], suggestions: [],
    selectedStrategy: strategyMode,
    selectedStrategyLabel: getStrategyLabel(strategyMode),
  }, container);
  renderResult(vm);
}

function performCalculation(inputData) {
  const { container, items, doorGap, topGap, sideGap, strategyMode } = inputData;
  const coloredItems = assignColors(items);
  const containerObj = {
    usableLength: container.length - doorGap,
    usableWidth: container.width - sideGap * 2,
    usableHeight: container.height - topGap,
    maxWeight: container.maxWeight,
  };
  const engineResult = planLoad(coloredItems, containerObj, { strategyMode });
  const vm = createViewModel(engineResult, container);
  renderResult(vm);
}

async function saveHistory(source, inputData, extraSummary = {}) {
  try {
    historyRecords = await historyApi.saveHistoryRecord({
      source,
      input: cloneCalculationInput(inputData),
      summary: extraSummary,
    });
  } catch {
    // 静默失败，不阻塞计算
  }
}

function handleCalculate(inputData, meta = {}) {
  const source = meta?.source || 'manual';
  latestCalculationInput = cloneCalculationInput(inputData);
  performCalculation(inputData);

  if (source === 'manual') {
    void saveHistory('quick-calc', inputData);
  }
  // history-load 和 result-strategy-switch 不写历史
}

function handleImport(payload) {
  const importResult = payload?.importResult || payload;
  const strategyMode = payload?.strategyMode;
  const containerType = payload?.containerType;
  const planningInput = transformImportResultToPlanInput(importResult, { strategyMode, containerType });
  const { container, items, doorGap, topGap, sideGap } = planningInput;

  latestCalculationInput = cloneCalculationInput({
    container, items, doorGap, topGap, sideGap,
    strategyMode: planningInput.strategyMode,
  });

  if (!items.length) {
    renderEmptyResult(container, planningInput.strategyMode);
    return;
  }

  performCalculation(latestCalculationInput);
  void saveHistory('excel-import', latestCalculationInput);
}

function handleResultStrategyChange(strategyMode) {
  if (!latestCalculationInput) return;
  latestCalculationInput = { ...cloneCalculationInput(latestCalculationInput), strategyMode };
  performCalculation(latestCalculationInput);
  // 切方案不写历史
}

resultPage.setOnTabChange(({ index }) => {
  if (index === 0) render2DIfNeeded();
  if (index === 1) render3DIfNeeded();
});

resultPage.setOnStrategyChange((strategyMode) => {
  handleResultStrategyChange(strategyMode);
});

shell.registerPage('quick-calc', '快速计算', () => createQuickCalcPage(handleCalculate, getQuickCalcPageOptions()));
shell.registerPage('import', 'Excel 导入', () => createImportPage(handleImport));
shell.registerPage('result', '计算结果', {
  render: () => resultPage.page,
  onShow: () => { if (latestViewModel) render3DIfNeeded(); },
  onHide: () => { dispose3DRenderer(); },
});

// 初始化：加载历史后显示首页
refreshHistory().then(() => {
  shell.showPage('quick-calc');
});
