import { getOrientations } from './orientation.js';
import { checkBoundary, checkLayerLimit, checkHeavyBottom, checkWeightCap } from './constraints.js';
import { EPSILON } from './epsilon.js';

export function placeSingleItem(ctx, item, opt, absX, absY, absZ, extra) {
  const { usableLength, usableWidth, usableHeight, strictStack, placements, supportMap, hardFailures } = ctx;
  const zLayer = Math.floor(absZ / opt.H) + 1;

  // Check heavy-bottom rule
  const footprintKey = `${absX}:${absY}:${opt.L}:${opt.W}:${zLayer - 1}`;
  if (!checkHeavyBottom(strictStack, item, zLayer - 1, supportMap.get(footprintKey) || [])) {
    hardFailures.push(`${item.name} 违反重下轻上规则`);
    return false;
  }

  // Check boundary
  if (!checkBoundary(absX, absY, absZ, opt.L, opt.W, opt.H, usableLength, usableWidth, usableHeight)) {
    hardFailures.push(`${item.name} 出现柜体越界摆放`);
    return false;
  }

  // Check layer limit
  if (!checkLayerLimit(item.layerRule, zLayer)) {
    hardFailures.push(`${item.name} 超过第4层限制`);
    return false;
  }

  // Place
  placements.push({
    name: item.name, color: item.color,
    absX, absY, absZ,
    L: opt.L, W: opt.W, H: opt.H,
    orientation: opt.name, layer: zLayer,
    isLight: item.isLight, density: item.density,
    layerRule: item.layerRule,
    ...extra,
  });

  // Update support map
  const upperKey = `${absX}:${absY}:${opt.L}:${opt.W}:${zLayer}`;
  const arr = supportMap.get(upperKey) || [];
  arr.push({ isLight: item.isLight, density: item.density });
  supportMap.set(upperKey, arr);

  return true;
}

export function calcBestOrientation(item, usableLength, usableWidth, usableHeight, cursorX) {
  const orientations = getOrientations(item);
  const remainingLength = usableLength - cursorX;
  let best = null;
  const diagnostics = [];

  for (const opt of orientations) {
    const cols = Math.floor(remainingLength / opt.L);
    const rows = Math.floor(usableWidth / opt.W);
    const layersRaw = Math.floor(usableHeight / opt.H);
    const effectiveLayers = item.layerRule === 'max4' ? Math.min(layersRaw, 4) : layersRaw;
    const capacity = cols * rows * effectiveLayers;

    if (cols <= 0 || rows <= 0 || effectiveLayers <= 0) {
      let reason = '';
      if (cols <= 0) reason = '剩余长度不足';
      else if (rows <= 0) reason = '宽度不足';
      else reason = '高度不足';
      if (item.layerRule === 'max4' && layersRaw > 4) reason += '，受仅1-4层限制';
      diagnostics.push({ orientation: opt.name, reason });
      continue;
    }

    diagnostics.push({ orientation: opt.name, reason: '该朝向可成立' });

    if (!best || capacity > best.capacity) {
      best = { ...opt, capacity, cols, rows, layers: effectiveLayers, diagnostics };
    }
  }

  if (!best) return null;
  best.diagnostics = diagnostics;
  return best;
}

export function runFloorPlan(items, container, options = {}) {
  const { strictStack = false } = options;
  const { usableLength, usableWidth, usableHeight, maxWeight } = container;

  const ctx = {
    usableLength, usableWidth, usableHeight,
    strictStack,
    placements: [],
    supportMap: new Map(),
    hardFailures: [],
  };

  let cursorX = 0;
  let totalQty = 0;
  let totalWeight = 0;
  let totalVolume = 0;
  const details = [];
  const failureDiagnostics = [];

  for (const item of items) {
    const best = calcBestOrientation(item, usableLength, usableWidth, usableHeight, cursorX);

    if (!best || best.capacity <= 0) {
      const diagText = (best?.diagnostics || []).map(d => `${d.orientation}：${d.reason}`).join(' | ');
      details.push({ ...item, actual: 0, rotated: '无合法朝向', reason: '所有合法朝向均无法在剩余柜体空间内成立', rootCause: '尺寸与剩余空间不匹配', diagnostics: diagText });
      failureDiagnostics.push({ name: item.name, plan: item.qty, actual: 0, diff: item.qty, rootCause: '尺寸与剩余空间不匹配', diagnostics: diagText || '所有朝向均失败' });
      continue;
    }

    const fitByWeight = checkWeightCap(item.weight, totalWeight, maxWeight);
    const fit = Math.max(0, Math.min(item.qty, best.capacity, fitByWeight));

    if (fit <= 0) {
      const rootCause = fitByWeight <= 0 ? '载重先达到上限' : '剩余空间先耗尽';
      const diagText = (best.diagnostics || []).map(d => `${d.orientation}：${d.reason}`).join(' | ');
      details.push({ ...item, actual: 0, rotated: best.name, reason: '受重量或剩余长度约束未能装入', rootCause, diagnostics: diagText });
      failureDiagnostics.push({ name: item.name, plan: item.qty, actual: 0, diff: item.qty, rootCause, diagnostics: diagText });
      continue;
    }

    const usedCols = Math.ceil(fit / (best.rows * best.layers));
    const usedLength = usedCols * best.L;

    if (cursorX + usedLength > usableLength + EPSILON) {
      const diagText = (best.diagnostics || []).map(d => `${d.orientation}：${d.reason}`).join(' | ');
      details.push({ ...item, actual: 0, rotated: best.name, reason: '剩余长度不足', rootCause: '剩余空间先耗尽', diagnostics: diagText });
      failureDiagnostics.push({ name: item.name, plan: item.qty, actual: 0, diff: item.qty, rootCause: '剩余空间先耗尽', diagnostics: diagText });
      continue;
    }

    let left = fit;
    for (let z = 0; z < best.layers; z++) {
      for (let y = 0; y < best.rows; y++) {
        for (let x = 0; x < usedCols; x++) {
          if (left <= 0) break;
          const absX = cursorX + x * best.L;
          const absY = y * best.W;
          const absZ = z * best.H;
          if (placeSingleItem(ctx, item, best, absX, absY, absZ, { mode: 'floor' })) {
            left--;
          }
        }
      }
    }

    const actual = fit - left;
    totalQty += actual;
    totalWeight += actual * item.weight;
    totalVolume += actual * item.L * item.W * item.H;
    cursorX += usedLength;

    details.push({
      ...item, actual, rotated: best.name,
      reason: actual < item.qty ? '部分装入' : '全部装入',
    });

    if (actual < item.qty) {
      failureDiagnostics.push({
        name: item.name, plan: item.qty, actual, diff: item.qty - actual,
        rootCause: '剩余空间或载重不足',
      });
    }
  }

  const containerVolume = usableLength * usableWidth * usableHeight;
  const volumeRate = containerVolume > 0 ? (totalVolume / containerVolume) * 100 : 0;
  const weightRate = maxWeight > 0 ? (totalWeight / maxWeight) * 100 : 0;

  return {
    placements: ctx.placements,
    details,
    failureDiagnostics,
    hardFailures: ctx.hardFailures,
    totalQty,
    totalWeight,
    totalVolume,
    cursorX,
    volumeRate,
    weightRate,
  };
}
