import { el } from './dom-helpers.js';

export function createAppShell(container) {
  const pages = new Map();
  let activePage = null;

  const nav = el('nav', { className: 'app-nav' });
  const content = el('main', { className: 'app-content' });

  container.appendChild(nav);
  container.appendChild(content);

  function registerPage(name, label, pageConfig) {
    const descriptor = typeof pageConfig === 'function' ? { render: pageConfig } : pageConfig;
    const button = el('button', {
      className: 'nav-tab',
      textContent: label,
      onClick: () => showPage(name),
    });
    nav.appendChild(button);
    pages.set(name, {
      btn: button,
      render: descriptor?.render || (() => null),
      onShow: descriptor?.onShow,
      onHide: descriptor?.onHide,
    });
  }

  function showPage(name) {
    if (activePage === name) return;

    const previousPage = activePage ? pages.get(activePage) : null;
    if (previousPage?.onHide) {
      previousPage.onHide();
    }

    activePage = name;
    for (const [key, page] of pages) {
      page.btn.classList.toggle('active', key === name);
    }

    content.innerHTML = '';
    const page = pages.get(name);
    if (page?.render) {
      const pageEl = page.render();
      if (pageEl) content.appendChild(pageEl);
    }
    if (page?.onShow) {
      page.onShow();
    }
  }

  return { registerPage, showPage, nav, content };
}
