import { STRATEGIES } from '../engine/scenario-runner.js';
import { el, table } from './dom-helpers.js';

export function createResultPage() {
  const totalQtyEl = el('span', { className: 'stat-value', textContent: '-' });
  const totalWeightEl = el('span', { className: 'stat-value', textContent: '-' });
  const volumeRateEl = el('span', { className: 'stat-value', textContent: '-' });
  const weightRateEl = el('span', { className: 'stat-value', textContent: '-' });
  const itemTypesEl = el('span', { className: 'stat-value', textContent: '-' });
  const selectedModeEl = el('p', { className: 'selected-mode', textContent: '当前方案模式：-' });
  const strategySwitchSelect = el('select', { className: 'result-strategy-select' });
  let onStrategyChange = null;
  let isUpdatingStrategySelect = false;

  for (const strategy of STRATEGIES) {
    strategySwitchSelect.appendChild(el('option', { value: strategy.name, textContent: strategy.label }));
  }

  strategySwitchSelect.addEventListener('change', () => {
    if (isUpdatingStrategySelect) return;
    if (onStrategyChange) {
      onStrategyChange(strategySwitchSelect.value);
    }
  });

  const strategySwitchBar = el('div', { className: 'result-strategy-switch' }, [
    el('label', { className: 'result-strategy-label', textContent: '结果页方案切换' }),
    strategySwitchSelect,
  ]);

  const summaryCards = el('div', { className: 'summary-cards' }, [
    el('div', { className: 'stat-card' }, [el('span', { className: 'stat-label', textContent: '装入箱数' }), totalQtyEl]),
    el('div', { className: 'stat-card' }, [el('span', { className: 'stat-label', textContent: '总重量(kg)' }), totalWeightEl]),
    el('div', { className: 'stat-card' }, [el('span', { className: 'stat-label', textContent: '体积利用率' }), volumeRateEl]),
    el('div', { className: 'stat-card' }, [el('span', { className: 'stat-label', textContent: '重量利用率' }), weightRateEl]),
    el('div', { className: 'stat-card' }, [el('span', { className: 'stat-label', textContent: '货物种类' }), itemTypesEl]),
  ]);

  const canvas2d = el('canvas', { className: 'plan-2d', id: 'plan2d' });
  const empty2d = el('p', { className: 'view-empty-message', textContent: '当前结果无可视化装载数据，请检查导入数据或切换方案模式。' });
  const view2dPanel = el('div', { className: 'result-visual-panel result-2d-panel' }, [canvas2d, empty2d]);

  const view3dContainer = el('div', { className: 'view-3d', id: 'view3d' });
  const empty3d = el('p', { className: 'view-empty-message', textContent: '当前结果无可视化装载数据，请检查导入数据或切换方案模式。' });
  const view3dPanel = el('div', { className: 'result-visual-panel result-3d-panel' }, [view3dContainer, empty3d]);

  const detailContainer = el('div', { className: 'detail-table' });
  const complianceContainer = el('div', { className: 'compliance-table' });
  const strategyContainer = el('div', { className: 'strategy-table' });
  const failureContainer = el('div', { className: 'failure-table' });

  const tabs = ['2D视图', '3D视图', '装载明细', '合规检查', '方案对比', '未装入分析'];
  const panels = [view2dPanel, view3dPanel, detailContainer, complianceContainer, strategyContainer, failureContainer];
  let activeTab = 0;
  let onTabChange = null;

  function activateTab(index) {
    activeTab = index;
    tabBar.querySelectorAll('.result-tab').forEach((button, buttonIndex) => button.classList.toggle('active', buttonIndex === index));
    panels.forEach((panel, panelIndex) => {
      panel.style.display = panelIndex === index ? 'block' : 'none';
    });
    if (onTabChange) {
      onTabChange({ index, label: tabs[index] });
    }
  }

  const tabBar = el('div', { className: 'result-tabs' });
  tabs.forEach((label, index) => {
    const button = el('button', {
      className: index === 0 ? 'result-tab active' : 'result-tab',
      textContent: label,
      onClick: () => activateTab(index),
    });
    tabBar.appendChild(button);
  });
  panels.forEach((panel, index) => {
    panel.style.display = index === 0 ? 'block' : 'none';
  });

  function setVisualState(hasPlacements) {
    empty2d.style.display = hasPlacements ? 'none' : 'block';
    empty3d.style.display = hasPlacements ? 'none' : 'block';
    view3dContainer.style.display = hasPlacements ? 'block' : 'none';
  }

  function update(vm) {
    if (!vm) return;

    totalQtyEl.textContent = String(vm.summary.totalQty);
    totalWeightEl.textContent = vm.summary.totalWeight;
    volumeRateEl.textContent = vm.summary.volumeRate;
    weightRateEl.textContent = vm.summary.weightRate;
    itemTypesEl.textContent = String(vm.summary.itemTypes);
    selectedModeEl.textContent = `当前方案模式：${vm.selectedMode?.label || '-'}`;
    isUpdatingStrategySelect = true;
    strategySwitchSelect.value = vm.selectedMode?.strategy || STRATEGIES[0].name;
    isUpdatingStrategySelect = false;
    setVisualState((vm.renderData?.placements || []).length > 0);

    detailContainer.textContent = '';
    if (vm.details.length > 0) {
      detailContainer.appendChild(table(
        ['货物', '尺寸', '朝向', '重量', '计划', '实际', '说明'],
        vm.details.map((detail) => [detail.name, detail.dimensions, detail.orientation, String(detail.weight), String(detail.planned), String(detail.actual), detail.reason]),
      ));
    }

    complianceContainer.textContent = '';
    if (vm.compliance.length > 0) {
      complianceContainer.appendChild(table(
        ['检查项', '结果', '说明'],
        vm.compliance.map((check) => [check.name, check.ok ? '通过' : '不通过', check.note]),
      ));
    }

    strategyContainer.textContent = '';
    if (vm.strategyComparison.length > 0) {
      strategyContainer.appendChild(table(
        ['输出', '排名', '策略', '装入数', '未装入', '体积率', '重量率', '均衡度', '说明'],
        vm.strategyComparison.map((strategy) => [
          strategy.selected ? '当前方案' : '-',
          String(strategy.rank),
          strategy.label,
          String(strategy.totalQty),
          String(strategy.unfitQty),
          strategy.volumeRate,
          strategy.weightRate,
          strategy.balanceDiff,
          strategy.reason,
        ]),
      ));
    }

    failureContainer.textContent = '';
    if (vm.failureDiagnostics.length > 0) {
      failureContainer.appendChild(table(
        ['货物', '计划', '实际', '差异', '主因', '诊断', '建议'],
        vm.failureDiagnostics.map((failure) => [
          failure.name,
          String(failure.planned),
          String(failure.actual),
          String(failure.diff),
          failure.rootCause,
          failure.diagnostics,
          failure.advice,
        ]),
      ));
    } else {
      failureContainer.appendChild(el('p', { textContent: '当前方案无未装入差异项。' }));
    }
  }

  const page = el('div', { className: 'result-page' }, [
    el('h2', { textContent: '计算结果' }),
    selectedModeEl,
    strategySwitchBar,
    summaryCards,
    tabBar,
    ...panels,
  ]);

  return {
    page,
    update,
    canvas2d,
    view3dContainer,
    setOnTabChange(handler) {
      onTabChange = handler;
    },
    setOnStrategyChange(handler) {
      onStrategyChange = handler;
    },
    is2DTabActive() {
      return activeTab === 0;
    },
    is3DTabActive() {
      return activeTab === 1;
    },
  };
}
