let currentView = 'top';
let currentLayerFocus = 0;

export function set2DView(mode) {
  currentView = mode;
}

export function stepLayer(delta, maxLayer) {
  currentLayerFocus = Math.max(0, Math.min(maxLayer, currentLayerFocus + delta));
  return currentLayerFocus;
}

export function getLayerFocus() {
  return currentLayerFocus;
}

export function setLayerFocus(layer) {
  currentLayerFocus = Math.max(0, layer);
}

export function draw2D(canvas, data, options = {}) {
  const { layerFocus = currentLayerFocus, layerOpacity = 0.28, view = currentView } = options;
  const dpr = (typeof window !== 'undefined' && window.devicePixelRatio) || 1;
  canvas.width = canvas.clientWidth * dpr;
  canvas.height = canvas.clientHeight * dpr;
  const ctx = canvas.getContext('2d');
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

  const W = canvas.clientWidth;
  const H = canvas.clientHeight;
  ctx.clearRect(0, 0, W, H);
  const pad = 24;

  const opacityBase = Math.max(0.05, Math.min(1, layerOpacity));

  let dims;
  if (view === 'front') {
    dims = { a: data.CL, b: data.CH, label: '正视图' };
  } else if (view === 'side') {
    dims = { a: data.CW, b: data.CH, label: '侧视图' };
  } else {
    dims = { a: data.CL, b: data.CW, label: '俯视图' };
  }

  const scale = Math.min((W - pad * 2) / dims.a, (H - pad * 2) / dims.b);
  const cw = dims.a * scale;
  const ch = dims.b * scale;
  const ox = (W - cw) / 2;
  const oy = (H - ch) / 2;

  ctx.fillStyle = '#f8fafc';
  ctx.fillRect(ox, oy, cw, ch);
  ctx.strokeStyle = '#111827';
  ctx.lineWidth = 2;
  ctx.strokeRect(ox, oy, cw, ch);

  ctx.fillStyle = '#111827';
  ctx.font = '14px Microsoft YaHei, sans-serif';
  ctx.fillText(`货柜${dims.label}（仅显示合法结果）`, ox, oy - 8);

  const paintedPallets = new Set();
  const sorted = [...(data.placements || [])].sort((a, b) => a.layer - b.layer);

  for (const p of sorted) {
    let x, y, w, h;
    if (view === 'front') {
      x = ox + p.absX * scale;
      y = oy + (data.CH - (p.absZ + p.H)) * scale;
      w = p.L * scale;
      h = p.H * scale;
    } else if (view === 'side') {
      x = ox + p.absY * scale;
      y = oy + (data.CH - (p.absZ + p.H)) * scale;
      w = p.W * scale;
      h = p.H * scale;
    } else {
      x = ox + p.absX * scale;
      y = oy + p.absY * scale;
      w = p.L * scale;
      h = p.W * scale;
    }

    const safeW = Math.max(0, Math.min(w, ox + cw - x));
    const safeH = Math.max(0, Math.min(h, oy + ch - y));
    if (safeW <= 0 || safeH <= 0) continue;

    if (view === 'top' && p.mode === 'pallet') {
      const key = `${p.palletX}-${p.palletY}`;
      if (!paintedPallets.has(key)) {
        paintedPallets.add(key);
        ctx.strokeStyle = '#94a3b8';
        ctx.setLineDash([6, 4]);
        ctx.strokeRect(ox + p.palletX * scale, oy + p.palletY * scale, p.palletL * scale, p.palletW * scale);
        ctx.setLineDash([]);
      }
    }

    ctx.save();
    const isFocus = layerFocus === 0 || p.layer === layerFocus;
    ctx.globalAlpha = isFocus ? 0.96 : opacityBase;
    ctx.fillStyle = '#' + (p.color || 0x4f46e5).toString(16).padStart(6, '0');
    ctx.fillRect(x + 1, y + 1, Math.max(0, safeW - 2), Math.max(0, safeH - 2));
    ctx.strokeStyle = isFocus ? '#ffffff' : 'rgba(255,255,255,0.5)';
    ctx.strokeRect(x + 1, y + 1, Math.max(0, safeW - 2), Math.max(0, safeH - 2));
    ctx.restore();
  }

  return { scale, ox, oy, cw, ch };
}

