import { generateId } from './identity.js';
import { validateFields } from './validation.js';

export const CONTAINER_SPECS = Object.freeze({
  '20GP': Object.freeze({ length: 5898, width: 2352, height: 2393, maxWeight: 21700 }),
  '40GP': Object.freeze({ length: 12032, width: 2352, height: 2393, maxWeight: 26500 }),
  '40HQ': Object.freeze({ length: 12032, width: 2352, height: 2698, maxWeight: 26500 }),
  '45HQ': Object.freeze({ length: 13556, width: 2352, height: 2698, maxWeight: 27700 }),
});

const VALID_TYPES = ['20GP', '40GP', '40HQ', '45HQ', 'custom'];

export function createContainer(input) {
  const { type, name, length, width, height, maxWeight, doorGap, topGap, sideGap } = input;
  validateFields('Container', [
    [VALID_TYPES.includes(type), `type must be: ${VALID_TYPES.join(', ')}`],
    [typeof name === 'string' && name.length > 0, 'name is required'],
    [typeof length === 'number' && isFinite(length) && length > 0, 'length must be positive (mm)'],
    [typeof width === 'number' && isFinite(width) && width > 0, 'width must be positive (mm)'],
    [typeof height === 'number' && isFinite(height) && height > 0, 'height must be positive (mm)'],
    [typeof maxWeight === 'number' && isFinite(maxWeight) && maxWeight > 0, 'maxWeight must be positive (kg)'],
    [typeof doorGap === 'number' && isFinite(doorGap) && doorGap >= 0, 'doorGap must be non-negative (mm)'],
    [typeof topGap === 'number' && isFinite(topGap) && topGap >= 0, 'topGap must be non-negative (mm)'],
    [typeof sideGap === 'number' && isFinite(sideGap) && sideGap >= 0, 'sideGap must be non-negative (mm)'],
  ]);
  return Object.freeze({
    id: generateId(), type, name, length, width, height, maxWeight, doorGap, topGap, sideGap,
  });
}
