export const CARGO_COLORS = Object.freeze([
  0x4f46e5, 0x059669, 0xd97706, 0xdc2626, 0x7c3aed,
  0x0891b2, 0xc026d3, 0x65a30d, 0xea580c, 0x2563eb,
  0x9333ea, 0x0d9488, 0xca8a04, 0xe11d48, 0x6d28d9,
  0x0284c7, 0xdb2777, 0x16a34a, 0xf97316, 0x1d4ed8,
]);

export function assignColors(items) {
  return items.map((item, index) => ({
    ...item,
    color: CARGO_COLORS[index % CARGO_COLORS.length],
  }));
}

export function formatRate(value) {
  return (value || 0).toFixed(1) + '%';
}

export function createViewModel(engineResult, container) {
  const { best, strategies, compliance, suggestions, selectedStrategy, selectedStrategyLabel } = engineResult;

  const summary = Object.freeze({
    totalQty: best ? best.totalQty : 0,
    totalWeight: best ? best.totalWeight.toFixed(1) : '0.0',
    volumeRate: formatRate(best ? best.volumeRate : 0),
    weightRate: formatRate(best ? best.weightRate : 0),
    itemTypes: best ? best.details.filter((detail) => detail.actual > 0).length : 0,
    balanceDiff: best ? best.balanceDiff.toFixed(1) + '%' : '0.0%',
    hasFailures: best ? best.failureDiagnostics.length > 0 : false,
    allCompliant: compliance ? compliance.every((check) => check.ok) : true,
  });

  const renderData = Object.freeze({
    CL: container.length,
    CW: container.width,
    CH: container.height,
    placements: best ? best.placements : [],
  });

  const strategyComparison = (strategies || []).map((strategy, index) => Object.freeze({
    rank: index + 1,
    strategy: strategy.strategy,
    label: strategy.label,
    selected: Boolean(strategy.selected),
    totalQty: strategy.totalQty,
    unfitQty: strategy.unfitQty || 0,
    volumeRate: formatRate(strategy.volumeRate),
    weightRate: formatRate(strategy.weightRate),
    balanceDiff: (strategy.balanceDiff || 0).toFixed(1) + '%',
    reason: strategy.selected
      ? '当前按所选模式输出'
      : index === 0
        ? '当前候选中综合最优'
        : strategy.totalQty < (strategies[0]?.totalQty || 0)
          ? `比最优少装 ${(strategies[0]?.totalQty || 0) - strategy.totalQty} 箱`
          : '与最优装箱数接近，但利用率/均衡性略弱',
  }));

  const details = best ? best.details.map((detail) => Object.freeze({
    name: detail.name,
    dimensions: `${detail.L || 0}×${detail.W || 0}×${detail.H || 0}`,
    orientation: detail.rotated || detail.orientation || '-',
    weight: detail.weight || 0,
    planned: detail.qty || 0,
    actual: detail.actual || 0,
    reason: detail.reason || '',
    rootCause: detail.rootCause || '',
  })) : [];

  const failureDiagnostics = best ? (best.failureDiagnostics || []).map((failure) => Object.freeze({
    name: failure.name,
    planned: failure.plan || 0,
    actual: failure.actual || 0,
    diff: failure.diff || 0,
    rootCause: failure.rootCause || '',
    diagnostics: failure.diagnostics || '-',
    advice: failure.advice || '-',
  })) : [];

  return Object.freeze({
    summary,
    renderData,
    selectedMode: Object.freeze({
      strategy: selectedStrategy,
      label: selectedStrategyLabel,
    }),
    strategyComparison: Object.freeze(strategyComparison),
    compliance: compliance ? Object.freeze(compliance.map((check) => Object.freeze({ ...check }))) : [],
    suggestions: suggestions ? Object.freeze(suggestions.map((suggestion) => Object.freeze({ ...suggestion }))) : [],
    details: Object.freeze(details),
    failureDiagnostics: Object.freeze(failureDiagnostics),
  });
}
