import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

export function create3DRenderer(containerEl) {
  let scene;
  let camera;
  let controls;
  let renderer = null;
  let animationId = null;
  const disposables = [];

  function getViewport() {
    return {
      width: Math.max(containerEl.clientWidth || 0, 1),
      height: Math.max(containerEl.clientHeight || 0, 1),
    };
  }

  function init() {
    dispose();

    scene = new THREE.Scene();
    scene.background = new THREE.Color(0xf8fafc);

    const viewport = getViewport();
    camera = new THREE.PerspectiveCamera(45, viewport.width / viewport.height, 0.1, 5000);

    renderer = new THREE.WebGLRenderer({ antialias: true, preserveDrawingBuffer: true });
    renderer.setSize(viewport.width, viewport.height);
    containerEl.appendChild(renderer.domElement);

    controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;

    const ambient = new THREE.AmbientLight(0xffffff, 1.1);
    const directional = new THREE.DirectionalLight(0xffffff, 1.2);
    directional.position.set(100, 200, 150);
    scene.add(ambient);
    scene.add(directional);
  }

  function setCamera(data, mode = 'iso') {
    if (!camera || !controls) return;
    const { CL, CW, CH } = data;
    if (mode === 'top') camera.position.set(CL / 2, Math.max(CH, CW) * 2.4, CW / 2 + 0.01);
    else if (mode === 'front') camera.position.set(CL / 2, CH / 2, CW * 2.6);
    else if (mode === 'side') camera.position.set(CL * 1.8, CH / 2, CW / 2);
    else camera.position.set(CL * 0.9, CH * 1.2, CW * 1.6);
    controls.target.set(CL / 2, CH / 2, CW / 2);
    controls.update();
  }

  function draw(data, cameraMode = 'iso') {
    if (!scene) init();

    while (scene.children.length > 2) {
      const child = scene.children[2];
      scene.remove(child);
      if (child.geometry) {
        child.geometry.dispose();
        const geometryIndex = disposables.indexOf(child.geometry);
        if (geometryIndex > -1) disposables.splice(geometryIndex, 1);
      }
      if (child.material) {
        child.material.dispose();
        const materialIndex = disposables.indexOf(child.material);
        if (materialIndex > -1) disposables.splice(materialIndex, 1);
      }
    }

    const containerGeometry = new THREE.BoxGeometry(data.CL, data.CH, data.CW);
    const containerMaterial = new THREE.MeshBasicMaterial({ color: 0x94a3b8, wireframe: true });
    const containerMesh = new THREE.Mesh(containerGeometry, containerMaterial);
    containerMesh.position.set(data.CL / 2, data.CH / 2, data.CW / 2);
    scene.add(containerMesh);
    disposables.push(containerGeometry, containerMaterial);

    const placements = data.placements || [];
    if (placements.length > 0) {
      const colorGroups = new Map();
      for (const placement of placements) {
        const colorKey = placement.color || 0x4f46e5;
        if (!colorGroups.has(colorKey)) colorGroups.set(colorKey, []);
        colorGroups.get(colorKey).push(placement);
      }

      for (const [color, group] of colorGroups) {
        const geometry = new THREE.BoxGeometry(1, 1, 1);
        const material = new THREE.MeshLambertMaterial({ color });
        const mesh = new THREE.InstancedMesh(geometry, material, group.length);

        const matrix = new THREE.Matrix4();
        for (let index = 0; index < group.length; index++) {
          const placement = group[index];
          matrix.makeScale(placement.L, placement.H, placement.W);
          matrix.setPosition(placement.absX + placement.L / 2, placement.absZ + placement.H / 2, placement.absY + placement.W / 2);
          mesh.setMatrixAt(index, matrix);
        }
        mesh.instanceMatrix.needsUpdate = true;
        scene.add(mesh);
        disposables.push(geometry, material);
      }
    }

    setCamera(data, cameraMode);

    if (animationId === null) {
      function animate() {
        animationId = requestAnimationFrame(animate);
        if (controls) controls.update();
        if (renderer && scene && camera) renderer.render(scene, camera);
      }
      animate();
    } else if (renderer && scene && camera) {
      renderer.render(scene, camera);
    }
  }

  function resize() {
    if (!renderer || !camera) return;
    const viewport = getViewport();
    camera.aspect = viewport.width / viewport.height;
    camera.updateProjectionMatrix();
    renderer.setSize(viewport.width, viewport.height);
    if (scene) renderer.render(scene, camera);
  }

  function dispose() {
    if (animationId !== null) {
      cancelAnimationFrame(animationId);
      animationId = null;
    }
    for (const disposable of disposables) {
      if (disposable && typeof disposable.dispose === 'function') disposable.dispose();
    }
    disposables.length = 0;
    if (controls) {
      controls.dispose();
      controls = null;
    }
    if (renderer) {
      renderer.dispose();
      if (renderer.domElement && renderer.domElement.parentNode) {
        renderer.domElement.parentNode.removeChild(renderer.domElement);
      }
      renderer = null;
    }
    scene = null;
    camera = null;
  }

  function getRenderer() {
    return renderer;
  }

  return { init, draw, setCamera, resize, dispose, getRenderer };
}
