import { CONTAINER_SPECS } from '../domain/container.js';
import { DEFAULT_STRATEGY } from '../engine/scenario-runner.js';
import { normalizeCartonDimensions } from './dimension-unit.js';

function toPositiveNumber(value, fallback = 0) {
  const num = Number(value);
  return Number.isFinite(num) && num > 0 ? num : fallback;
}

function getDirectCartonQty(record) {
  return Math.max(
    toPositiveNumber(record?.actual_carton_count),
    toPositiveNumber(record?.carton_count),
    toPositiveNumber(record?.requested_carton_count),
    0,
  );
}

function getDerivedCartonQty(record) {
  const cartonPackSize = toPositiveNumber(record?.carton_pack_size);
  const demandQty = Math.max(
    toPositiveNumber(record?.actual_required_qty),
    toPositiveNumber(record?.warehouse_total_qty),
    toPositiveNumber(record?.requested_qty),
    0,
  );

  if (cartonPackSize > 0 && demandQty > 0) {
    return Math.ceil(demandQty / cartonPackSize);
  }

  return 0;
}

function inspectRecordQty(record) {
  const directCartonQty = getDirectCartonQty(record);
  if (directCartonQty > 0) {
    return { qty: directCartonQty, source: 'direct-carton-count' };
  }

  const derivedCartonQty = getDerivedCartonQty(record);
  if (derivedCartonQty > 0) {
    return { qty: derivedCartonQty, source: 'row-derived' };
  }

  return { qty: 0, source: 'unresolved' };
}

function buildQuantityContext(importResult) {
  const cartons = Array.isArray(importResult?.cartons) ? importResult.cartons : [];
  const demandLines = Array.isArray(importResult?.demandLines) ? importResult.demandLines : [];

  const demandLinesByProduct = new Map();
  for (const line of demandLines) {
    if (!line?.product_code) continue;
    const existing = demandLinesByProduct.get(line.product_code) || [];
    existing.push(line);
    demandLinesByProduct.set(line.product_code, existing);
  }

  const cartonCountsByProduct = new Map();
  for (const carton of cartons) {
    if (!carton?.product_code) continue;
    cartonCountsByProduct.set(carton.product_code, (cartonCountsByProduct.get(carton.product_code) || 0) + 1);
  }

  return { demandLinesByProduct, cartonCountsByProduct };
}

function getUniqueDemandLine(productCode, context) {
  const matches = context.demandLinesByProduct.get(productCode) || [];
  return matches.length === 1 ? matches[0] : null;
}

function resolveCartonQty(carton, context) {
  const cartonQty = inspectRecordQty(carton);
  if (cartonQty.qty > 0) {
    return cartonQty;
  }

  const productCode = carton?.product_code;
  const uniqueDemandLine = getUniqueDemandLine(productCode, context);
  const cartonCountForProduct = context.cartonCountsByProduct.get(productCode) || 0;
  if (!uniqueDemandLine || cartonCountForProduct !== 1) {
    return { qty: 0, source: 'unresolved' };
  }

  const demandQty = inspectRecordQty(uniqueDemandLine);
  if (demandQty.qty > 0) {
    return { qty: demandQty.qty, source: 'demand-line-derived' };
  }

  return { qty: 0, source: 'unresolved' };
}

function formatPreviewValue(value) {
  return value > 0 ? String(value) : '-';
}

function getQuantitySourceLabel(source) {
  if (source === 'direct-carton-count') return '原始箱数字段';
  if (source === 'row-derived') return '按当前行推导';
  if (source === 'demand-line-derived') return '按需求行推导';
  return '无法可靠推导';
}

function deriveItems(importResult) {
  const rawCartons = Array.isArray(importResult?.cartons) ? importResult.cartons : [];
  const { cartons, unit } = normalizeCartonDimensions(rawCartons);
  const productNames = new Map(
    (Array.isArray(importResult?.products) ? importResult.products : [])
      .filter((product) => product?.product_code)
      .map((product) => [product.product_code, product.product_name]),
  );
  const quantityContext = buildQuantityContext({ ...importResult, cartons });

  const grouped = new Map();

  for (const carton of cartons) {
    const productCode = carton?.product_code || '未命名货物';
    const demandLine = getUniqueDemandLine(productCode, quantityContext);
    const L = toPositiveNumber(carton?.outer_length_mm);
    const W = toPositiveNumber(carton?.outer_width_mm);
    const H = toPositiveNumber(carton?.outer_height_mm);
    const weight = toPositiveNumber(carton?.gross_weight_kg, toPositiveNumber(carton?.net_weight_kg, 1));
    const { qty } = resolveCartonQty(carton, quantityContext);

    if (L <= 0 || W <= 0 || H <= 0 || qty <= 0) continue;

    const layerRule = carton?.stack_limit_rule || demandLine?.stack_limit_rule || 'none';
    const sideAllowed = carton?.rotation_allowed ?? demandLine?.rotation_allowed ?? true;
    const key = [productCode, L, W, H, weight, layerRule, sideAllowed].join('|');
    const existing = grouped.get(key);
    if (existing) {
      existing.qty += qty;
      continue;
    }

    grouped.set(key, {
      name: productNames.get(productCode) || productCode,
      productCode,
      L,
      W,
      H,
      weight,
      qty,
      heavy: weight >= 20,
      isLight: weight <= 8,
      density: 0,
      layerRule,
      sideAllowed,
      color: 0x4f46e5,
    });
  }

  return { items: Array.from(grouped.values()), unit };
}

export function getImportPreviewRows(importResult, limit = 10) {
  const rawCartons = Array.isArray(importResult?.cartons) ? importResult.cartons : [];
  const { cartons } = normalizeCartonDimensions(rawCartons);
  const quantityContext = buildQuantityContext({ ...importResult, cartons });

  return cartons.slice(0, limit).map((carton) => {
    const rawCartonQty = getDirectCartonQty(carton);
    const resolvedQty = resolveCartonQty(carton, quantityContext);

    return {
      productCode: carton?.product_code || '-',
      length: String(carton?.outer_length_mm || '-'),
      width: String(carton?.outer_width_mm || '-'),
      height: String(carton?.outer_height_mm || '-'),
      weight: String(carton?.gross_weight_kg || '-'),
      rawCartonQty: formatPreviewValue(rawCartonQty),
      calculatedQty: formatPreviewValue(resolvedQty.qty),
      quantitySource: getQuantitySourceLabel(resolvedQty.source),
    };
  });
}

export function transformImportResultToPlanInput(importResult, options = {}) {
  const containerType = options.containerType && CONTAINER_SPECS[options.containerType] ? options.containerType : '40HQ';
  const defaultContainer = options.container || { type: containerType, ...CONTAINER_SPECS[containerType] };
  const { items, unit } = deriveItems(importResult);

  return {
    container: defaultContainer,
    items,
    doorGap: options.doorGap || 0,
    topGap: options.topGap || 0,
    sideGap: options.sideGap || 0,
    strategyMode: options.strategyMode || DEFAULT_STRATEGY,
    dimensionUnit: unit,
  };
}
