function toPositiveNumber(value) {
  const num = Number(value);
  return Number.isFinite(num) && num > 0 ? num : 0;
}

export function detectDimensionUnit(records = []) {
  const dims = [];
  for (const record of records) {
    for (const key of ['outer_length_mm', 'outer_width_mm', 'outer_height_mm']) {
      const value = toPositiveNumber(record?.[key]);
      if (value > 0) dims.push(value);
    }
  }

  if (dims.length === 0) {
    return { inputUnit: 'unknown', scaleToMm: 1, normalizedUnit: 'mm' };
  }

  const max = Math.max(...dims);
  const median = dims.slice().sort((a, b) => a - b)[Math.floor(dims.length / 2)];

  // Heuristic:
  // - common carton dims in cm are often 20~80
  // - common carton dims in mm are often 200~1500
  if (max <= 100 && median <= 80) {
    return { inputUnit: 'cm', scaleToMm: 10, normalizedUnit: 'mm' };
  }

  return { inputUnit: 'mm', scaleToMm: 1, normalizedUnit: 'mm' };
}

export function normalizeCartonDimensions(cartons = []) {
  const unit = detectDimensionUnit(cartons);
  const normalized = cartons.map((carton) => ({
    ...carton,
    outer_length_mm: toPositiveNumber(carton?.outer_length_mm) * unit.scaleToMm,
    outer_width_mm: toPositiveNumber(carton?.outer_width_mm) * unit.scaleToMm,
    outer_height_mm: toPositiveNumber(carton?.outer_height_mm) * unit.scaleToMm,
  }));

  return { cartons: normalized, unit };
}
